func TestParsePushoverPriority(t *testing.T) {
	cases := map[string]int{
		"lowest":    -2,
		"low":       -1,
		"normal":    0,
		"high":      1,
		"emergency": 2,
		"2":         2,
	}
	for input, want := range cases {
		got, err := parsePushoverPriority(input)
		if err != nil {
			t.Fatalf("parsePushoverPriority(%q): %v", input, err)
		}
		if got != want {
			t.Fatalf("parsePushoverPriority(%q) = %d, want %d", input, got, want)
		}
	}
	if _, err := parsePushoverPriority("page-me-hard"); err == nil {
		t.Fatal("invalid priority accepted")
	}
}

func TestValidateNotifyEmergencyOptions(t *testing.T) {
	base := notifyOptions{
		appToken:     "app",
		userKey:      "user",
		message:      "body",
		pollInterval: 5 * time.Second,
		watchTimeout: time.Minute,
	}
	if err := validateNotifyOptions(base, 0, &rootFlags{}); err != nil {
		t.Fatalf("normal notify rejected: %v", err)
	}
	emergency := base
	emergency.retry = 30
	emergency.expire = 120
	if err := validateNotifyOptions(emergency, 2, &rootFlags{}); err != nil {
		t.Fatalf("valid emergency rejected: %v", err)
	}
	emergency.retry = 29
	if err := validateNotifyOptions(emergency, 2, &rootFlags{}); err == nil {
		t.Fatal("emergency retry below 30 accepted")
	}

	// --cancel-on-timeout has no meaning without --watch (the cancellation
	// fires from inside the watch loop). Accepting the combo silently
	// would leave an emergency retry chain paging the recipient while
	// the user believed it was cancelled, so the validator must reject.
	cancelWithoutWatch := base
	cancelWithoutWatch.retry = 30
	cancelWithoutWatch.expire = 120
	cancelWithoutWatch.cancelOnTimeout = true
	if err := validateNotifyOptions(cancelWithoutWatch, 2, &rootFlags{}); err == nil {
		t.Fatal("--cancel-on-timeout without --watch was accepted under --priority emergency")
	}

	// The same combo WITH --watch is the documented usage and must still pass.
	cancelWithWatch := cancelWithoutWatch
	cancelWithWatch.watch = true
	if err := validateNotifyOptions(cancelWithWatch, 2, &rootFlags{}); err != nil {
		t.Fatalf("--cancel-on-timeout --watch under emergency rejected: %v", err)
	}
}

func TestApplyPushoverEnvDefaults(t *testing.T) {
	t.Setenv("PUSHOVER_APP_TOKEN", "app-env")
	t.Setenv("PUSHOVER_USER_KEY", "user-env")

	flags := &rootFlags{}
	cmd := newNotifyCmd(flags)
	if err := applyPushoverEnvDefaults(cmd); err != nil {
		t.Fatalf("applyPushoverEnvDefaults: %v", err)
	}
	appToken, _ := cmd.Flags().GetString("app-token")
	userKey, _ := cmd.Flags().GetString("user-key")
	if appToken != "app-env" || userKey != "user-env" {
		t.Fatalf("env defaults not applied: app=%q user=%q", appToken, userKey)
	}
	if !cmd.Flags().Changed("app-token") || !cmd.Flags().Changed("user-key") {
		t.Fatal("env defaults did not mark canonical flags as changed")
	}
}

func TestApplyPushoverEnvDefaultsReplacesExamplesPlaceholder(t *testing.T) {
	t.Setenv("PUSHOVER_APP_TOKEN", "app-env")

	flags := &rootFlags{}
	cmd := newQuotaCmd(flags)
	if err := cmd.Flags().Set("app-token", "your-token-here"); err != nil {
		t.Fatalf("set app-token: %v", err)
	}
	if err := applyPushoverEnvDefaults(cmd); err != nil {
		t.Fatalf("applyPushoverEnvDefaults: %v", err)
	}
	appToken, _ := cmd.Flags().GetString("app-token")
	if appToken != "app-env" {
		t.Fatalf("placeholder was not replaced by env default: %q", appToken)
	}
}

func TestNotifyDryRunDoesNotRecordHistory(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "history.db")
	cmd := newRootCmd(&rootFlags{})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	cmd.SetArgs([]string{"notify", "--dry-run", "--app-token", "app", "--user-key", "user", "--message", "hello", "--history-db", dbPath})
	if err := cmd.Execute(); err != nil {
		t.Fatalf("dry-run notify: %v", err)
	}
	records, err := listNotificationHistory(context.Background(), dbPath, "", 10)
	if err != nil {
		t.Fatalf("listNotificationHistory: %v", err)
	}
	if len(records) != 0 {
		t.Fatalf("dry-run recorded %d history rows, want 0", len(records))
	}
}

func TestNotificationHistoryStoresRecipientHash(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "history.db")
	_, err := recordNotificationHistory(context.Background(), dbPath, notificationHistoryRecord{
		Command:        "notify",
		StatusCode:     200,
		Success:        true,
		Priority:       0,
		MessagePreview: "hello",
		RecipientHash:  hashForHistory("secret-user-key"),
		Response:       map[string]any{"status": float64(1), "request": "req"},
	})
	if err != nil {
		t.Fatalf("recordNotificationHistory: %v", err)
	}
	records, err := listNotificationHistory(context.Background(), dbPath, "", 10)
	if err != nil {
		t.Fatalf("listNotificationHistory: %v", err)
	}
	if len(records) != 1 {
		t.Fatalf("history rows = %d, want 1", len(records))
	}
	if records[0].RecipientHash == "secret-user-key" || records[0].RecipientHash == "" {
		t.Fatalf("recipient hash not stored safely: %q", records[0].RecipientHash)
	}
}

func TestWatchEmergencyReceiptBypassesCachedReceiptStatus(t *testing.T) {
	requests := 0
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requests++
		w.Header().Set("Content-Type", "application/json")
		status := map[string]any{
			"status":       1,
			"acknowledged": 0,
			"expired":      0,
			"called_back":  0,
		}
		if requests > 1 {
			status["acknowledged"] = 1
		}
		if err := json.NewEncoder(w).Encode(status); err != nil {
			t.Fatalf("encode response: %v", err)
		}
	}))
	defer server.Close()

	c := client.New(&config.Config{BaseURL: server.URL}, time.Second, 0)
	result, err := watchEmergencyReceipt(context.Background(), c, &rootFlags{}, "token", "receipt", 5*time.Second, 20*time.Second, false)
	if err != nil {
		t.Fatalf("watchEmergencyReceipt: %v", err)
	}
	if intFromAny(result["acknowledged"]) != 1 {
		t.Fatalf("watch did not observe acknowledged status: %#v", result)
	}
	if requests < 2 {
		t.Fatalf("watch reused cached receipt status; requests=%d", requests)
	}
}
